// JavaScript implementation for Next.js Developer Troubleshooting Part 5C
async function handleExecution(payload) {
  try {
    const response = await fetch('/api/data', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await response.json();
    console.log('Next.js Developer Troubleshooting Part 5C status:', data.success);
    return data;
  } catch (err) {
    console.error('Execution error:', err);
  }
}

handleExecution({ item: 'Next.js Developer Troubleshooting Part 5C' });
